INSERT INTO `wp_postmeta` VALUES (1,2,'_wp_page_template','default'),(2,3,'_wp_page_template','default'),(3,5,'_form','<label> Your name\n    [text* your-name autocomplete:name] </label>\n\n<label> Your email\n    [email* your-email autocomplete:email] </label>\n\n<label> Subject\n    [text* your-subject] </label>\n\n<label> Your message (optional)\n    [textarea your-message] </label>\n\n[submit \"Submit\"]'),(4,5,'_mail','a:8:{s:7:\"subject\";s:30:\"[_site_title] \"[your-subject]\"\";s:6:\"sender\";s:32:\"[_site_title] <admin@alasca.dev>\";s:4:\"body\";s:191:\"From: [your-name] [your-email]\nSubject: [your-subject]\n\nMessage Body:\n[your-message]\n\n-- \nThis is a notification that a contact form was submitted on your website ([_site_title] [_site_url]).\";s:9:\"recipient\";s:19:\"[_site_admin_email]\";s:18:\"additional_headers\";s:22:\"Reply-To: [your-email]\";s:11:\"attachments\";s:0:\"\";s:8:\"use_html\";i:0;s:13:\"exclude_blank\";i:0;}'),(5,5,'_mail_2','a:9:{s:6:\"active\";b:0;s:7:\"subject\";s:30:\"[_site_title] \"[your-subject]\"\";s:6:\"sender\";s:32:\"[_site_title] <admin@alasca.dev>\";s:4:\"body\";s:220:\"Message Body:\n[your-message]\n\n-- \nThis email is a receipt for your contact form submission on our website ([_site_title] [_site_url]) in which your email address was used. If that was not you, please ignore this message.\";s:9:\"recipient\";s:12:\"[your-email]\";s:18:\"additional_headers\";s:29:\"Reply-To: [_site_admin_email]\";s:11:\"attachments\";s:0:\"\";s:8:\"use_html\";i:0;s:13:\"exclude_blank\";i:0;}'),(6,5,'_messages','a:12:{s:12:\"mail_sent_ok\";s:45:\"Thank you for your message. It has been sent.\";s:12:\"mail_sent_ng\";s:71:\"There was an error trying to send your message. Please try again later.\";s:16:\"validation_error\";s:61:\"One or more fields have an error. Please check and try again.\";s:4:\"spam\";s:71:\"There was an error trying to send your message. Please try again later.\";s:12:\"accept_terms\";s:69:\"You must accept the terms and conditions before sending your message.\";s:16:\"invalid_required\";s:27:\"Please fill out this field.\";s:16:\"invalid_too_long\";s:32:\"This field has a too long input.\";s:17:\"invalid_too_short\";s:33:\"This field has a too short input.\";s:13:\"upload_failed\";s:46:\"There was an unknown error uploading the file.\";s:24:\"upload_file_type_invalid\";s:49:\"You are not allowed to upload files of this type.\";s:21:\"upload_file_too_large\";s:31:\"The uploaded file is too large.\";s:23:\"upload_failed_php_error\";s:38:\"There was an error uploading the file.\";}'),(7,5,'_additional_settings',''),(8,5,'_locale','en_US'),(9,5,'_hash','c9358c3ce3d4657e167a45d5db5980af3293101c99372769ad2b55f3e5c32665'),(10,6,'_form','<div class=\"space-y-3\">\n[text* your-name id:hero-name class:input-field class:mb-2  placeholder \"Nome\"]\n[email* your-email id:hero-email class:input-field class:mb-2 placeholder \"E-mail\"]\n[tel* your-phone id:hero-phone class:input-field class:mb-2 placeholder \"Telefone\"]\n[submit class:btn-cta \"QUERO ADVOGAR NESTA ├üREA\"]\n</div>'),(11,7,'_form','<div class=\"space-y-3\">[text* your-name id:participar-name class:input-field-alt placeholder \"Seu nome completo\"][email* your-email id:participar-email class:input-field-alt placeholder \"Seu melhor e-mail\"][tel* your-phone id:participar-phone class:input-field-alt placeholder \"Seu WhatsApp (com DDD)\"][submit class:btn-cta-alt \"QUERO ADVOGAR NESTA ├üREA\"]</div>'),(12,6,'_messages','a:22:{s:12:\"mail_sent_ok\";s:0:\"\";s:12:\"mail_sent_ng\";s:0:\"\";s:16:\"validation_error\";s:0:\"\";s:4:\"spam\";s:0:\"\";s:12:\"accept_terms\";s:0:\"\";s:16:\"invalid_required\";s:0:\"\";s:16:\"invalid_too_long\";s:0:\"\";s:17:\"invalid_too_short\";s:0:\"\";s:13:\"upload_failed\";s:0:\"\";s:24:\"upload_file_type_invalid\";s:0:\"\";s:21:\"upload_file_too_large\";s:0:\"\";s:23:\"upload_failed_php_error\";s:0:\"\";s:12:\"invalid_date\";s:0:\"\";s:14:\"date_too_early\";s:0:\"\";s:13:\"date_too_late\";s:0:\"\";s:14:\"invalid_number\";s:0:\"\";s:16:\"number_too_small\";s:0:\"\";s:16:\"number_too_large\";s:0:\"\";s:23:\"quiz_answer_not_correct\";s:0:\"\";s:13:\"invalid_email\";s:0:\"\";s:11:\"invalid_url\";s:0:\"\";s:11:\"invalid_tel\";s:0:\"\";}'),(13,4,'_yoast_wpseo_title','Imers├úo em Direito Imobili├írio ÔÇö Advogue nas demandas mais rent├íveis'),(14,4,'_yoast_wpseo_metadesc','Em 3 dias, descubra como advogar nas demandas rent├íveis do Direito Imobili├írio e faturar acima de R.000,00 em honor├írios por contrato. Evento online e ao vivo com Jaylton Lopes Jr.'),(15,4,'_yoast_wpseo_focuskw','Direito Imobili├írio'),(16,6,'_mail','a:9:{s:6:\"active\";b:1;s:7:\"subject\";s:0:\"\";s:6:\"sender\";s:0:\"\";s:9:\"recipient\";s:16:\"admin@alasca.dev\";s:4:\"body\";s:0:\"\";s:18:\"additional_headers\";s:0:\"\";s:11:\"attachments\";s:0:\"\";s:8:\"use_html\";b:0;s:13:\"exclude_blank\";b:0;}'),(17,6,'_mail_2','a:9:{s:6:\"active\";b:0;s:7:\"subject\";s:0:\"\";s:6:\"sender\";s:0:\"\";s:9:\"recipient\";s:0:\"\";s:4:\"body\";s:0:\"\";s:18:\"additional_headers\";s:0:\"\";s:11:\"attachments\";s:0:\"\";s:8:\"use_html\";b:0;s:13:\"exclude_blank\";b:0;}'),(18,6,'_additional_settings',''),(19,6,'_locale','en_US'),(20,6,'_hash','014504685e8c940806ad60817b03c614c7fdc4c04b058de8f04735367424cff9'),(22,6,'_config_validation','a:3:{s:12:\"mail.subject\";a:1:{i:0;a:2:{s:4:\"code\";s:11:\"maybe_empty\";s:4:\"args\";a:3:{s:7:\"message\";s:32:\"There is a possible empty field.\";s:6:\"params\";a:0:{}s:4:\"link\";s:57:\"https://contactform7.com/configuration-errors/maybe-empty\";}}}s:11:\"mail.sender\";a:1:{i:0;a:2:{s:4:\"code\";s:22:\"invalid_mailbox_syntax\";s:4:\"args\";a:3:{s:7:\"message\";s:31:\"Invalid mailbox syntax is used.\";s:6:\"params\";a:0:{}s:4:\"link\";s:68:\"https://contactform7.com/configuration-errors/invalid-mailbox-syntax\";}}}s:9:\"mail.body\";a:1:{i:0;a:2:{s:4:\"code\";s:11:\"maybe_empty\";s:4:\"args\";a:3:{s:7:\"message\";s:32:\"There is a possible empty field.\";s:6:\"params\";a:0: